(function(){const a=()=>{const e=document.querySelector(".nav-toggle"),t=document.querySelector(".site-nav");if(!e||!t||e.dataset.navBound==="true")return;e.dataset.navBound="true";const o=()=>{t.classList.remove("is-open"),e.setAttribute("aria-expanded","false")};e.addEventListener("click",()=>{const n=t.classList.toggle("is-open");e.setAttribute("aria-expanded",String(n))}),t.querySelectorAll(".nav-link").forEach(n=>{n.addEventListener("click",o)})};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",a,{once:!0}):a()})();
